import React, { useState } from 'react';
import InputSection from './InputSection';
import OutputSection from './OutputSection';
import AdvancedParameters from './AdvancedParameters';
import BatchGenerator from './BatchGenerator';
import { GenerationSettings, GenerationResult } from '../types';

interface MainContentProps {
  sidebarOpen: boolean;
  settings: GenerationSettings;
  currentOutput: GenerationResult | null;
  isGenerating: boolean;
  onGenerate: (result: GenerationResult) => void;
  onSetGenerating: (generating: boolean) => void;
  onToggleFavorite: (id: string) => void;
  isFavorite: boolean;
  history: GenerationResult[];
  onSettingsChange: (settings: Partial<GenerationSettings>) => void;
  onFeedbackSubmit?: (feedback: any) => void;
}

const MainContent: React.FC<MainContentProps> = ({
  sidebarOpen,
  settings,
  currentOutput,
  isGenerating,
  onGenerate,
  onSetGenerating,
  onToggleFavorite,
  isFavorite,
  history,
  onSettingsChange,
  onFeedbackSubmit
}) => {
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [showBatch, setShowBatch] = useState(false);

  return (
    <main className={`flex-1 transition-all duration-300 ${
      sidebarOpen ? 'ml-80' : 'ml-0'
    } p-4`}>
      <div className="max-w-5xl mx-auto space-y-6">
        {/* Input Section */}
        <InputSection
          settings={settings}
          onGenerate={onGenerate}
          isGenerating={isGenerating}
          onSetGenerating={onSetGenerating}
          history={history}
        />

        {/* Toggle Buttons for Advanced Features */}
        <div className="flex gap-3 justify-center">
          <button
            onClick={() => setShowAdvanced(!showAdvanced)}
            className={`glass-button rounded-lg px-4 py-2 text-sm transition-all ${
              showAdvanced ? 'bg-white/25 text-white' : 'text-white/70 hover:text-white'
            }`}
          >
            {showAdvanced ? '✓ ' : ''}Advanced Parameters
          </button>
          <button
            onClick={() => setShowBatch(!showBatch)}
            className={`glass-button rounded-lg px-4 py-2 text-sm transition-all ${
              showBatch ? 'bg-white/25 text-white' : 'text-white/70 hover:text-white'
            }`}
          >
            {showBatch ? '✓ ' : ''}Batch Generation
          </button>
        </div>

        {/* Advanced Parameters Panel */}
        {showAdvanced && (
          <AdvancedParameters
            settings={settings}
            onSettingsChange={onSettingsChange}
            disabled={isGenerating}
          />
        )}

        {/* Batch Generator Panel */}
        {showBatch && (
          <BatchGenerator
            settings={settings}
            onBatchComplete={(results) => {
              console.log('Batch complete:', results);
            }}
          />
        )}

        {/* Output Section */}
        {(currentOutput || isGenerating) && (
          <OutputSection
            result={currentOutput}
            isGenerating={isGenerating}
            onToggleFavorite={onToggleFavorite}
            isFavorite={isFavorite}
            settings={settings}
            onFeedbackSubmit={onFeedbackSubmit || (() => {})}
          />
        )}
      </div>
    </main>
  );
};

export default MainContent;