import React from 'react';
import Orb from './Orb';
import './LandingPage.css';

interface LandingPageProps {
  onGetStarted: () => void;
}

const LandingPage: React.FC<LandingPageProps> = ({ onGetStarted }) => {
  return (
    <div className="landing-page">
      {/* Orb Background */}
      <div className="landing-background">
        <Orb
          hoverIntensity={0}
          rotateOnHover={true}
          hue={360}
          forceHoverState={false}
          backgroundColor="#000000"
        />
      </div>

      {/* Content Overlay */}
      <div className="landing-content">
        <div className="landing-hero">
          <h1 className="landing-title">
            <span className="title-main">MelodAI</span>
            <span className="title-subtitle">Create Music with AI</span>
          </h1>
          
          <p className="landing-description">
            Transform your ideas into beautiful music using advanced AI technology. 
            Generate unique compositions, explore different styles, and bring your musical vision to life.
          </p>

          <div className="landing-features">
            <div className="feature-item">
              <div className="feature-icon">🎵</div>
              <span>AI-Powered Generation</span>
            </div>
            <div className="feature-item">
              <div className="feature-icon">🎨</div>
              <span>Creative Control</span>
            </div>
            <div className="feature-item">
              <div className="feature-icon">⚡</div>
              <span>Instant Results</span>
            </div>
          </div>

          <button 
            className="get-started-btn"
            onClick={onGetStarted}
          >
            <span>Get Started</span>
            <div className="btn-glow"></div>
          </button>
        </div>
      </div>
    </div>
  );
};

export default LandingPage;